"use client";

import { useEffect, useState } from "react";
import { Requisition, Budget } from "@/types";
import { getRequisitions, updateRequisitionStatus } from "@/lib/requisitions";
import { getBudgets } from "@/lib/budgets";
import { getSpendAnalytics } from "@/lib/analytics";
import { useAuth } from "@/context/AuthContext";
import { formatCurrency } from "@/lib/currencies";
import { useModal } from "@/context/ModalContext";

import CustomSelect from "@/components/ui/CustomSelect";
import ApprovalDetailModal from "@/components/approvals/ApprovalDetailModal";

export default function ApprovalsPage() {
    const { user } = useAuth();
    const { showConfirm, showError } = useModal();
    const [pendingApprovals, setPendingApprovals] = useState<Requisition[]>([]);
    const [loading, setLoading] = useState(true);

    // Modal State
    const [selectedReq, setSelectedReq] = useState<Requisition | null>(null);
    const [deptBudget, setDeptBudget] = useState<Budget | undefined>(undefined);
    const [deptSpend, setDeptSpend] = useState(0);

    // For Demo: Simulate being a specific manager if not logged in with a matching UID
    const [simulatedRole, setSimulatedRole] = useState('auth-it-manager');

    const fetchApprovals = async () => {
        setLoading(true);
        const allReqs = await getRequisitions();

        // Filter for requests assigned to me (or my simulated role)
        // AND that are still PENDING
        const myPending = allReqs.filter(r =>
            r.status === 'PENDING' &&
            (r.approverId === user?.uid || r.approverId === simulatedRole)
        );

        setPendingApprovals(myPending.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime()));
        setLoading(false);
    };

    useEffect(() => {
        fetchApprovals();
    }, [user, simulatedRole]);

    // Fetch Budget Data when opening a request
    const handleOpenRequest = async (req: Requisition) => {
        try {
            const [budgets, analytics] = await Promise.all([
                getBudgets(),
                getSpendAnalytics() // This would ideally filter by dept in a real backend API
            ]);

            const budget = budgets.find(b => b.department === req.department);
            const spend = analytics.spendByDepartment[req.department] || 0;

            setDeptBudget(budget);
            setDeptSpend(spend);
            setSelectedReq(req);
        } catch (error) {
            console.error("Error fetching budget context", error);
            // Open modal anyway, just without budget context
            setSelectedReq(req);
        }
    };

    const handleAction = async (id: string, action: 'APPROVED' | 'REJECTED') => {
        // If rejecting, maybe force a comment? (Simplified for now)
        const confirmed = await showConfirm(
            "Confirm Action",
            `Are you sure you want to ${action} this request?`
        );

        if (!confirmed) return;

        try {
            await updateRequisitionStatus(id, action);
            setSelectedReq(null); // Close modal
            fetchApprovals(); // Refresh list
        } catch (e) {
            await showError("Error", "Error updating status");
        }
    };

    if (loading) return <div>Loading approvals...</div>;

    return (
        <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
                <div>
                    <h1 style={{ fontSize: '1.875rem', fontWeight: 'bold', color: 'var(--primary)' }}>My Approvals</h1>
                    <p style={{ color: 'var(--text-secondary)' }}>Review requests awaiting your authorization.</p>
                </div>

                {/* Simulator for Demo Purposes */}
                <div style={{ padding: '0.5rem', background: '#e0f2fe', borderRadius: '8px', fontSize: '0.8rem', display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <span style={{ fontWeight: 600 }}>Simulated Role:</span>
                    <div style={{ width: '250px' }}>
                        <CustomSelect
                            value={simulatedRole}
                            onChange={setSimulatedRole}
                            options={[
                                { label: "IT Manager (Limit $1k)", value: "auth-it-manager" },
                                { label: "IT Director (Limit $5k)", value: "auth-it-director" },
                                { label: "Finance Controller (Unlimited)", value: "auth-finance" }
                            ]}
                        />
                    </div>
                </div>
            </div>

            {pendingApprovals.length === 0 ? (
                <div className="card" style={{ textAlign: 'center', padding: '3rem' }}>
                    <p style={{ color: 'var(--text-secondary)' }}>You're all caught up! No pending approvals.</p>
                </div>
            ) : (
                <div className="card" style={{ overflowX: 'auto', padding: 0 }}>
                    <table style={{ width: '100%', borderCollapse: 'collapse', textAlign: 'left' }}>
                        <thead style={{ backgroundColor: 'var(--background)', borderBottom: '1px solid var(--border)' }}>
                            <tr>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Date</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Requester</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Dept</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Vendor</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Amount</th>
                                <th style={{ padding: '1rem', fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {pendingApprovals.map((req) => (
                                <tr key={req.id} style={{ borderBottom: '1px solid var(--border)' }}>
                                    <td style={{ padding: '1rem', fontSize: '0.9rem' }}>{req.createdAt.toLocaleDateString()}</td>
                                    <td style={{ padding: '1rem', fontWeight: 500 }}>{req.requesterName}</td>
                                    <td style={{ padding: '1rem' }}>
                                        <span style={{ padding: '0.25rem 0.5rem', border: '1px solid var(--border)', borderRadius: '4px', fontSize: '0.8rem', color: 'var(--text-secondary)' }}>
                                            {req.department}
                                        </span>
                                    </td>
                                    <td style={{ padding: '1rem' }}>{req.vendorName || '-'}</td>
                                    <td style={{ padding: '1rem', fontWeight: 600 }}>{formatCurrency(req.totalAmount, req.currency)}</td>
                                    <td style={{ padding: '1rem' }}>
                                        <button
                                            onClick={() => handleOpenRequest(req)}
                                            style={{
                                                backgroundColor: 'var(--accent)', color: 'white', border: 'none',
                                                padding: '0.5rem 1rem', borderRadius: '4px', cursor: 'pointer', fontSize: '0.875rem'
                                            }}
                                        >
                                            Review Request
                                        </button>
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}

            {/* Detail Modal */}
            {selectedReq && (
                <ApprovalDetailModal
                    requisition={selectedReq}
                    budget={deptBudget}
                    deptSpend={deptSpend}
                    onClose={() => setSelectedReq(null)}
                    onApprove={(id) => handleAction(id, 'APPROVED')}
                    onReject={(id) => handleAction(id, 'REJECTED')}
                />
            )}
        </div>
    );
}
