"use client";

import { useMemo } from "react";
import { Requisition, Budget } from "@/types";
import { formatCurrency } from "@/lib/currencies";

interface ApprovalDetailModalProps {
    requisition: Requisition;
    budget?: Budget; // Optional: Budget for the department
    deptSpend: number; // Total spend for the department so far
    onClose: () => void;
    onApprove: (id: string) => void;
    onReject: (id: string) => void;
}

export default function ApprovalDetailModal({
    requisition,
    budget,
    deptSpend,
    onClose,
    onApprove,
    onReject
}: ApprovalDetailModalProps) {

    // Calculate Budget Impact
    const impact = useMemo(() => {
        if (!budget) return null;

        const currentUsage = (deptSpend / budget.amount) * 100;
        const purchaseImpact = (requisition.totalAmount / budget.amount) * 100;
        const newUsage = currentUsage + purchaseImpact;

        return {
            currentUsage,
            newUsage,
            isOverBudget: newUsage > 100,
            remaining: budget.amount - deptSpend - requisition.totalAmount
        };
    }, [budget, deptSpend, requisition.totalAmount]);

    return (
        <div style={{
            position: 'fixed', inset: 0, zIndex: 50,
            backgroundColor: 'rgba(0,0,0,0.5)', backdropFilter: 'blur(4px)',
            display: 'flex', alignItems: 'center', justifyContent: 'center', p: '1rem'
        }}>
            <div className="card" style={{
                width: '800px', maxWidth: '95%', maxHeight: '90vh', overflowY: 'auto',
                animation: 'slideIn 0.3s ease-out'
            }}>
                {/* Header */}
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', marginBottom: '1.5rem', borderBottom: '1px solid var(--border)', paddingBottom: '1rem' }}>
                    <div>
                        <div style={{ fontSize: '0.875rem', color: 'var(--text-secondary)', marginBottom: '0.25rem' }}>
                            Request #{requisition.id?.slice(-6).toUpperCase()}
                        </div>
                        <h2 style={{ fontSize: '1.5rem', fontWeight: 'bold' }}>{requisition.items[0]?.description || 'Purchase Request'}</h2>
                        <div style={{ display: 'flex', gap: '1rem', marginTop: '0.5rem' }}>
                            <span style={{ padding: '0.25rem 0.5rem', background: '#e0f2fe', color: '#0369a1', borderRadius: '4px', fontSize: '0.8rem', fontWeight: 600 }}>
                                {requisition.department}
                            </span>
                            <span style={{ padding: '0.25rem 0.5rem', background: '#f3f4f6', color: '#374151', borderRadius: '4px', fontSize: '0.8rem' }}>
                                by {requisition.requesterName}
                            </span>
                            <span style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', display: 'flex', alignItems: 'center' }}>
                                📅 {requisition.createdAt.toLocaleDateString()}
                            </span>
                        </div>
                    </div>
                    <div style={{ textAlign: 'right' }}>
                        <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: 'var(--primary)' }}>
                            {formatCurrency(requisition.totalAmount, requisition.currency)}
                        </div>
                        <div style={{ fontSize: '0.875rem', color: 'var(--text-secondary)' }}>Total Value</div>
                    </div>
                </div>

                <div style={{ display: 'grid', gridTemplateColumns: 'minmax(0, 2fr) minmax(0, 1fr)', gap: '2rem' }}>

                    {/* Left Column: Details */}
                    <div>
                        {/* Budget Insight */}
                        {budget && impact && (
                            <div style={{ marginBottom: '2rem', padding: '1rem', background: 'var(--background)', borderRadius: '8px', border: '1px solid var(--border)' }}>
                                <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: '0.75rem' }}>Budget Impact Analysis</h3>

                                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: '0.875rem', marginBottom: '0.5rem' }}>
                                    <span>Current Spend: {formatCurrency(deptSpend, budget.currency)}</span>
                                    <span>Budget: {formatCurrency(budget.amount, budget.currency)}</span>
                                </div>

                                <div style={{ height: '12px', width: '100%', backgroundColor: '#e5e7eb', borderRadius: '6px', overflow: 'hidden', position: 'relative' }}>
                                    {/* Existing Spend */}
                                    <div style={{ position: 'absolute', left: 0, top: 0, bottom: 0, width: `${Math.min(impact.currentUsage, 100)}%`, backgroundColor: '#94a3b8' }}></div>
                                    {/* This Request (Impact) */}
                                    <div style={{
                                        position: 'absolute',
                                        left: `${Math.min(impact.currentUsage, 100)}%`,
                                        top: 0, bottom: 0,
                                        width: `${Math.min(impact.newUsage - impact.currentUsage, 100 - impact.currentUsage)}%`,
                                        backgroundColor: impact.isOverBudget ? 'var(--error)' : 'var(--primary)',
                                        opacity: 0.8
                                    }}></div>
                                </div>

                                <div style={{ marginTop: '0.5rem', fontSize: '0.8rem', color: impact.isOverBudget ? 'var(--error)' : 'var(--success)' }}>
                                    {impact.isOverBudget
                                        ? `⚠️ This request will exceed the budget by ${formatCurrency(Math.abs(impact.remaining), budget.currency)}`
                                        : `✅ Budget remaining after approval: ${formatCurrency(impact.remaining, budget.currency)}`
                                    }
                                </div>
                            </div>
                        )}

                        {/* Line Items */}
                        <div style={{ marginBottom: '2rem' }}>
                            <h3 style={{ fontSize: '1rem', fontWeight: 600, marginBottom: '0.75rem' }}>Line Items</h3>
                            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem' }}>
                                <thead style={{ borderBottom: '1px solid var(--border)', textAlign: 'left' }}>
                                    <tr>
                                        <th style={{ padding: '0.5rem' }}>Item</th>
                                        <th style={{ padding: '0.5rem' }}>Qty</th>
                                        <th style={{ padding: '0.5rem' }}>Unit Price</th>
                                        <th style={{ padding: '0.5rem' }}>Total</th>
                                    </tr>
                                </thead>
                                <tbody>
                                    {requisition.items.map((item, i) => (
                                        <tr key={i} style={{ borderBottom: '1px solid #f3f4f6' }}>
                                            <td style={{ padding: '0.75rem 0.5rem' }}>
                                                <div style={{ fontWeight: 500 }}>{item.description}</div>
                                                {item.glCode && <div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>GL: {item.glCode}</div>}
                                            </td>
                                            <td style={{ padding: '0.75rem 0.5rem' }}>{item.quantity}</td>
                                            <td style={{ padding: '0.75rem 0.5rem' }}>{formatCurrency(item.unitPrice, requisition.currency)}</td>
                                            <td style={{ padding: '0.75rem 0.5rem', fontWeight: 600 }}>{formatCurrency(item.total, requisition.currency)}</td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    </div>

                    {/* Right Column: Context */}
                    <div>
                        <div style={{ marginBottom: '1.5rem' }}>
                            <h3 style={{ fontSize: '0.9rem', fontWeight: 600, marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Vendor</h3>
                            <div style={{ fontSize: '1rem', fontWeight: 500 }}>{requisition.vendorName || 'N/A'}</div>
                        </div>

                        <div style={{ marginBottom: '1.5rem' }}>
                            <h3 style={{ fontSize: '0.9rem', fontWeight: 600, marginBottom: '0.5rem', color: 'var(--text-secondary)' }}>Business Purpose</h3>
                            <p style={{ fontSize: '0.9rem', lineHeight: '1.5', padding: '0.75rem', backgroundColor: '#f9fafb', borderRadius: '4px', border: '1px solid var(--border)' }}>
                                {requisition.justification}
                            </p>
                        </div>
                    </div>

                </div>

                {/* Footer Actions */}
                <div style={{ display: 'flex', justifyContent: 'flex-end', gap: '1rem', marginTop: '2rem', paddingTop: '1rem', borderTop: '1px solid var(--border)' }}>
                    <button
                        onClick={onClose}
                        style={{ padding: '0.75rem 1.5rem', borderRadius: '6px', border: '1px solid var(--border)', backgroundColor: 'white', cursor: 'pointer' }}
                    >
                        Close
                    </button>
                    <button
                        onClick={() => onReject(requisition.id!)}
                        style={{ padding: '0.75rem 1.5rem', borderRadius: '6px', backgroundColor: 'var(--error)', color: 'white', border: 'none', cursor: 'pointer', fontWeight: 500 }}
                    >
                        Reject Request
                    </button>
                    <button
                        onClick={() => onApprove(requisition.id!)}
                        style={{ padding: '0.75rem 2rem', borderRadius: '6px', backgroundColor: 'var(--success)', color: 'white', border: 'none', cursor: 'pointer', fontWeight: 600, boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }}
                    >
                        Approve Request
                    </button>
                </div>
            </div>
        </div>
    );
}
